import{_ as l,o as e,c as i,ag as t}from"./chunks/framework.CXIqMST4.js";const u=JSON.parse('{"title":"沙盒、审批与安全边界","description":"","frontmatter":{},"headers":[],"relativePath":"guide/06-sandbox-approvals.md","filePath":"guide/06-sandbox-approvals.md","lastUpdated":1777684488000}'),o={name:"guide/06-sandbox-approvals.md"};function d(r,a,s,n,p,c){return e(),i("div",null,[...a[0]||(a[0]=[t('<h1 id="沙盒、审批与安全边界" tabindex="-1">沙盒、审批与安全边界 <a class="header-anchor" href="#沙盒、审批与安全边界" aria-label="Permalink to &quot;沙盒、审批与安全边界&quot;">​</a></h1><p>Codex 可以读取文件、修改代码、运行命令。能力越强，越需要清楚的边界。</p><h2 id="你需要关心什么" tabindex="-1">你需要关心什么 <a class="header-anchor" href="#你需要关心什么" aria-label="Permalink to &quot;你需要关心什么&quot;">​</a></h2><p>重点不是“信不信任 AI”，而是把风险拆开：</p><ul><li>文件系统：能读写哪些目录。</li><li>网络：是否允许访问外网。</li><li>命令：是否允许安装依赖、启动服务、跑迁移。</li><li>凭据：是否可能接触密钥、token、cookie。</li><li>数据：是否会修改数据库、对象存储或生产资源。</li></ul><h2 id="低风险任务" tabindex="-1">低风险任务 <a class="header-anchor" href="#低风险任务" aria-label="Permalink to &quot;低风险任务&quot;">​</a></h2><p>通常可以较快推进：</p><ul><li>修改文档。</li><li>补充测试。</li><li>修复本地可复现 bug。</li><li>更新非敏感配置。</li><li>运行项目已有的测试命令。</li></ul><h2 id="高风险任务" tabindex="-1">高风险任务 <a class="header-anchor" href="#高风险任务" aria-label="Permalink to &quot;高风险任务&quot;">​</a></h2><p>建议先确认计划：</p><ul><li>删除文件或批量移动文件。</li><li>数据库迁移。</li><li>修改认证、权限、支付、账单逻辑。</li><li>访问生产服务。</li><li>上传、下载或处理敏感数据。</li><li>引入新依赖或大规模升级依赖。</li></ul><h2 id="给-codex-的安全提示词" tabindex="-1">给 Codex 的安全提示词 <a class="header-anchor" href="#给-codex-的安全提示词" aria-label="Permalink to &quot;给 Codex 的安全提示词&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请在动手前先说明你计划运行的命令和可能影响的文件。不要读取 `.env`、密钥、token 或任何私有凭据。不要执行删除数据、发布、部署或迁移命令，除非我明确确认。</span></span></code></pre></div><h2 id="团队建议" tabindex="-1">团队建议 <a class="header-anchor" href="#团队建议" aria-label="Permalink to &quot;团队建议&quot;">​</a></h2><ul><li>在 <code>AGENTS.md</code> 写清楚禁止事项。</li><li>把高风险命令放进人工审批流程。</li><li>给测试、lint、类型检查提供明确命令。</li><li>避免把生产凭据放在普通开发环境里。</li><li>对 Codex 产出的 PR 仍然执行正常代码审查。</li></ul>',15)])])}const b=l(o,[["render",d]]);export{u as __pageData,b as default};
